   259→    add('taskId', obj.taskId);
   260→    add('agent', obj.agentName || obj.agentId);
   261→    add('bytes', obj.bytesWritten);
   262→    if (Array.isArray(obj.agents)) add('agents', obj.agents.length);
   263→    if (Array.isArray(obj.tasks)) add('tasks', obj.tasks.length);
   264→    if (obj.path && !chips.some((chip) => chip.startsWith('path:'))) add('path', obj.path);
   265→  }
   266→
   267→  if (chips.length === 0) {
   268→    add('tool', name);
