   315→  killAgent(agentId: string) {
   316→    const instance = this.resolveAgent(agentId);
   317→    if (!instance) return;
   318→    const remainingRuns: QueuedRun[] = [];
   319→    for (const run of this.queuedRuns) {
   320→      if (run.agentId === instance.id) {
   321→        run.cancel();
   322→      } else {
   323→        remainingRuns.push(run);
   324→      }
   325→    }
   326→    this.queuedRuns = remainingRuns;
   327→    const ac = this.abortControllers.get(instance.id);
   328→    ac?.abort();
   329→    this.abortControllers.delete(instance.id);
   330→    if (instance.status === "queued" || instance.status === "running") {
   331→      instance.status = "cancelled";
   332→      instance.completedAt = Date.now();
