    56→  const maxLimit = customMaxIterations || definition.maxIterations;
    57→
    58→  while (iterations < maxLimit) {
    59→    if (signal?.aborted) throw new Error("Sub-agent aborted");
    60→    iterations++;
    61→
    62→    onProgress?.(`${definition.name}: Iteration ${iterations}/${maxLimit} - requesting model response`, messages);
    63→
