   124→      const invocations = responseMsg.tool_calls.map((tc: any) => ({
   125→        id: Math.random().toString(36).substring(7),
   126→        name: tc.function.name,
   127→        args: tc.function.arguments,
   128→        status: "running" as const
   129→      }));
   130→
   131→      const asstMsg: ChatMessage = {
   132→        id: Math.random().toString(36),
   133→        role: "assistant",
   134→        content: responseMsg.content || "",
   135→        toolInvocations: invocations,
   136→        geminiParts: responseMsg.geminiParts
   137→      };
   138→      messages.push(asstMsg);
   139→      onProgress?.(`${definition.name}: selected ${invocations.length} tool call${invocations.length === 1 ? "" : "s"}`, messages);
   140→
   141→      // Execute tools
   142→      for (const inv of invocations) {
   143→        if (!definition.allowedTools.includes(inv.name)) {
   144→          inv.result = JSON.stringify({ error: `Tool "${inv.name}" is not allowed for ${definition.name}` });
   145→          inv.status = "error";
   146→          onProgress?.(`${definition.name}: blocked disallowed tool ${inv.name}`, messages);
   147→          continue;
   148→        }
   149→        try {
   150→          onProgress?.(`${definition.name}: using ${inv.name}`, messages);
   151→          const result = await executeToolCallFn(
   152→            inv.name,
   153→            inv.args,
   154→            workspaceId,
   155→            settings,
   156→            (chunk: string) => {
   157→              inv.result = typeof chunk === "string" ? chunk : JSON.stringify(chunk);
   158→              onProgress?.(`${definition.name}: streaming ${inv.name}`, messages);
   159→            },
   160→            signal
   161→          );
   162→          inv.result = typeof result === "string" ? result : JSON.stringify(result);
   163→          inv.status = "success";
   164→          onProgress?.(`${definition.name}: completed ${inv.name}`, messages);
   165→        } catch (err: any) {
   166→          inv.result = JSON.stringify({ error: err.message });
   167→          inv.status = "error";
   168→          onProgress?.(`${definition.name}: ${inv.name} failed`, messages);
   169→        }
   170→      }
   171→
   172→      messages.push({
   173→        id: Math.random().toString(36),
   174→        role: "tool",
   175→        content: "",
   176→        toolInvocations: invocations
   177→      });
   178→      onProgress?.(`${definition.name}: tool results recorded`, messages);
   179→    } else {
   180→      // Final text response — sub-agent is done
   181→      messages.push({
   182→        id: Math.random().toString(36),
   183→        role: "assistant",
   184→        content: responseMsg.content,
   185→        geminiParts: responseMsg.geminiParts
   186→      });
   187→      onProgress?.(`${definition.name}: final response ready`, messages);
   188→      
   189→      return { result: responseMsg.content, messages };
   190→    }
   191→  }
   192→
   193→  return { 
   194→    result: `Sub-agent ${definition.name} reached maximum iterations (${maxLimit})`,
   195→    messages 
   196→  };
   197→}
