     1→import { useEffect, useState } from 'react';
     2→
     3→export function useTerminalTabs(workspaceId: string) {
     4→  const [tabs, setTabs] = useState<string[]>(() => {
     5→    if (typeof window !== 'undefined') {
     6→      const saved = localStorage.getItem(`terminal_tabs_${workspaceId}`);
     7→      return saved ? JSON.parse(saved) : ['1'];
     8→    }
     9→    return ['1'];
    10→  });
    11→
    12→  const [activeTabId, setActiveTabId] = useState<string>(() => {
    13→    if (typeof window !== 'undefined') {
    14→      const saved = localStorage.getItem(`terminal_active_tab_${workspaceId}`);
    15→      return saved || '1';
    16→    }
    17→    return '1';
    18→  });
    19→
    20→  useEffect(() => {
    21→    localStorage.setItem(`terminal_tabs_${workspaceId}`, JSON.stringify(tabs));
    22→  }, [tabs, workspaceId]);
    23→
    24→  useEffect(() => {
    25→    localStorage.setItem(`terminal_active_tab_${workspaceId}`, activeTabId);
    26→  }, [activeTabId, workspaceId]);
    27→
    28→  const addTab = () => {
    29→    const nextId = String(Math.max(...tabs.map(t => parseInt(t, 10) || 1), 0) + 1);
    30→    setTabs(prev => [...prev, nextId]);
    31→    setActiveTabId(nextId);
    32→  };
    33→
    34→  const removeTab = (tabIdToRemove: string, e: React.MouseEvent) => {
    35→    e.stopPropagation();
    36→    if (tabs.length === 1) return;
    37→    if (activeTabId === tabIdToRemove) {
    38→      const nextActive = tabs.find(t => t !== tabIdToRemove) || '1';
    39→      setActiveTabId(nextActive);
    40→    }
    41→    setTabs(prev => prev.filter(t => t !== tabIdToRemove));
    42→  };
    43→
    44→  return { tabs, activeTabId, setActiveTabId, addTab, removeTab };
    45→}
