  const ts = Date.now().toString(36);
  const rand = Math.random().toString(36).slice(2, 6);
  if (label) {
    const slug = label
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, '-')
      .replace(/^-+|-+$/g, '')
      .slice(0, 24);
    return `${slug}-${rand}`;
  }
  return `agent-${ts}-${rand}`;
}

