    29→  window.dispatchEvent(new CustomEvent(name, { detail: task }));
    30→}
    31→
    32→export class AgentTaskManager {
    33→  private tasks: Map<string, AgentTask> = new Map();
    34→
    35→  constructor() {
    36→    this.restore();
    37→  }
    38→
    39→  create(input: Omit<AgentTask, "id" | "startedAt" | "updatedAt" | "status"> & { status?: AgentTaskStatus }) {
    40→    const now = Date.now();
    41→    const task: AgentTask = {
    42→      ...input,
    43→      id: makeTaskId(),
    44→      status: input.status || "running",
    45→      startedAt: now,
    46→      updatedAt: now,
    47→    };
    48→    this.tasks.set(task.id, task);
    49→    this.persist();
    50→    dispatchTaskEvent("agent-task-updated", task);
    51→    return task;
    52→  }
    53→
    54→  update(taskId: string, patch: Partial<AgentTask>) {
    55→    const existing = this.tasks.get(taskId);
    56→    if (!existing) return undefined;
    57→
    58→    const status = patch.status || existing.status;
    59→    const task: AgentTask = {
    60→      ...existing,
    61→      ...patch,
    62→      status,
    63→      updatedAt: Date.now(),
    64→      completedAt: ["completed", "error", "cancelled"].includes(status) ? (patch.completedAt || existing.completedAt || Date.now()) : patch.completedAt,
    65→    };
    66→
    67→    this.tasks.set(taskId, task);
    68→    this.persist();
