    80→  list() {
    81→    return Array.from(this.tasks.values()).sort((a, b) => b.updatedAt - a.updatedAt);
    82→  }
    83→
    84→  clearCompleted() {
    85→    for (const [id, task] of this.tasks.entries()) {
    86→      if (["completed", "error", "cancelled"].includes(task.status)) {
    87→        this.tasks.delete(id);
    88→      }
    89→    }
    90→    this.persist();
    91→  }
