    25→// 1. TypeScript AST Parser
    26→function parseTypeScript(filePath: string, content: string): Omit<CodeChunk, 'filePath'>[] {
    27→  const sourceFile = ts.createSourceFile(
    28→    filePath,
    29→    content,
    30→    ts.ScriptTarget.Latest,
    31→    true
    32→  );
    33→
    34→  const symbols: Omit<CodeChunk, 'filePath'>[] = [];
    35→
    36→  function visit(node: ts.Node) {
    37→    if (
    38→      ts.isFunctionDeclaration(node) ||
    39→      ts.isClassDeclaration(node) ||
    40→      ts.isInterfaceDeclaration(node) ||
    41→      ts.isMethodDeclaration(node)
    42→    ) {
    43→      const name = node.name ? node.name.getText(sourceFile) : 'anonymous';
    44→      const type = ts.isFunctionDeclaration(node) ? 'function' :
    45→                   ts.isClassDeclaration(node) ? 'class' :
    46→                   ts.isInterfaceDeclaration(node) ? 'interface' : 'method';
    47→      
    48→      const startPos = node.getStart(sourceFile);
    49→      const endPos = node.getEnd();
    50→      
    51→      const { line: startLine } = sourceFile.getLineAndCharacterOfPosition(startPos);
    52→      const { line: endLine } = sourceFile.getLineAndCharacterOfPosition(endPos);
    53→      
    54→      symbols.push({
    55→        name,
    56→        type,
    57→        startLine: startLine + 1,
    58→        endLine: endLine + 1,
    59→        content: node.getText(sourceFile)
    60→      });
    61→    }
    62→    ts.forEachChild(node, visit);
    63→  }
    64→
    65→  visit(sourceFile);
    66→  return symbols;
    67→}
