    69→// 2. Python Symbol Parser
    70→function parsePython(content: string): Omit<CodeChunk, 'filePath'>[] {
    71→  const lines = content.split('\n');
    72→  const symbols: Omit<CodeChunk, 'filePath'>[] = [];
    73→  
    74→  for (let i = 0; i < lines.length; i++) {
    75→    const line = lines[i];
    76→    const funcMatch = line.match(/^\s*def\s+([a-zA-Z0-9_]+)\s*\(/);
    77→    const classMatch = line.match(/^\s*class\s+([a-zA-Z0-9_]+)\s*[:\(]/);
    78→    
    79→    if (funcMatch || classMatch) {
    80→      const name = funcMatch ? funcMatch[1] : classMatch![1];
    81→      const type = funcMatch ? 'function' : 'class';
    82→      const startLine = i + 1;
    83→      
    84→      const indentMatch = line.match(/^(\s*)/);
    85→      const indent = indentMatch ? indentMatch[1].length : 0;
    86→      let endLine = startLine;
    87→      
    88→      for (let j = i + 1; j < lines.length; j++) {
    89→        const nextLine = lines[j];
    90→        if (nextLine.trim() === '') continue;
    91→        const nextIndentMatch = nextLine.match(/^(\s*)/);
    92→        const nextIndent = nextIndentMatch ? nextIndentMatch[1].length : 0;
    93→        
    94→        if (nextIndent <= indent && !nextLine.trim().startsWith('#')) {
    95→          endLine = j;
    96→          break;
    97→        }
    98→        endLine = j + 1;
    99→      }
   100→      
   101→      symbols.push({
   102→        name,
   103→        type,
   104→        startLine,
   105→        endLine,
   106→        content: lines.slice(startLine - 1, endLine).join('\n')
   107→      });
   108→    }
   109→  }
   110→  return symbols;
   111→}
