   113→// 3. Fallback generic text chunker (by line size)
   114→function genericChunk(content: string, linesPerChunk = 50): Omit<CodeChunk, 'filePath'>[] {
   115→  const lines = content.split('\n');
   116→  const chunks: Omit<CodeChunk, 'filePath'>[] = [];
   117→  
   118→  for (let i = 0; i < lines.length; i += linesPerChunk) {
   119→    const slice = lines.slice(i, i + linesPerChunk);
   120→    chunks.push({
   121→      name: `chunk-${Math.floor(i / linesPerChunk) + 1}`,
   122→      type: 'generic-chunk',
   123→      startLine: i + 1,
   124→      endLine: i + slice.length,
   125→      content: slice.join('\n')
   126→    });
   127→  }
   128→  return chunks;
   129→}
