    59→  // Helper to parse typed target into our reverse proxy path
    60→  const parseUrl = (input: string): string => {
    61→    const trimmed = input.trim();
    62→    if (!trimmed) return '/proxy/5173/';
    63→
    64→    // 1. If it's a pure number like "5173" or "8000"
    65→    if (/^\d+$/.test(trimmed)) {
    66→      return `/proxy/${trimmed}/`;
    67→    }
    68→
    69→    // 2. If it contains localhost/127.0.0.1 and a port
    70→    const portMatch = trimmed.match(/(?:localhost|127\.0\.0\.1|127\.0\.0\.1\s*):(\d+)(.*)/i);
    71→    if (portMatch) {
    72→      const port = portMatch[1];
    73→      const subpath = portMatch[2] || '/';
    74→      return `/proxy/${port}${subpath}`;
    75→    }
    76→
    77→    // 3. If it starts with http:// or https://
    78→    if (trimmed.startsWith('http://') || trimmed.startsWith('https://')) {
    79→      try {
    80→        const parsed = new URL(trimmed);
    81→        if (parsed.hostname === 'localhost' || parsed.hostname === '127.0.0.1') {
    82→          return `/proxy/${parsed.port || '80'}${parsed.pathname}${parsed.search}`;
    83→        }
    84→      } catch (e) {}
    85→      return trimmed;
    86→    }
    87→
    88→    // 4. Robust Port Extraction Fallback: If there is any colon followed by a port number anywhere, extract it!
    89→    const anyPortMatch = trimmed.match(/:(\d+)/);
    90→    if (anyPortMatch) {
    91→      const port = anyPortMatch[1];
    92→      const afterPortMatch = trimmed.match(new RegExp(`:${port}(.*)`));
    93→      const subpath = (afterPortMatch && afterPortMatch[1]) || '/';
    94→      return `/proxy/${port}${subpath}`;
    95→    }
    96→
    97→    return trimmed;
    98→  };
