   124→
   125→      if (!iframeDoc) {
   126→        return { success: false, error: 'غير قادر على الوصول إلى محتوى الـ Iframe. تأكد من أن الخادم يعمل بنفس أصل الصفحة.' };
   127→      }
   128→
   129→      switch (action.type) {
   130→        case 'click': {
   131→          const el = iframeDoc.querySelector(action.selector);
   132→          if (!el) {
   133→            return { success: false, error: `لم يتم العثور على أي عنصر بال_selector المحدد: ${action.selector}` };
   134→          }
   135→          (el as HTMLElement).click();
   136→          el.dispatchEvent(new Event('click', { bubbles: true }));
   137→          addLog(`🤖 نقر آلي على عنصر: "${action.selector}"`, 'success');
