   139→        }
   140→        case 'type': {
   141→          const el = iframeDoc.querySelector(action.selector) as HTMLInputElement | HTMLTextAreaElement;
   142→          if (!el) {
   143→            return { success: false, error: `لم يتم العثور على حقل الإدخال بال_selector: ${action.selector}` };
   144→          }
   145→          el.value = action.text || '';
