   164→          addLog(`🤖 تحديث الصفحة آليًا`, 'info');
   165→          return { success: true, url: iframeWindow?.location.href || '', html: 'جاري تحديث الصفحة...' };
   166→        }
   167→        case 'get-html': {
   168→          addLog(`🤖 جلب نسخة من كود الـ HTML لاستكشاف الأخطاء`, 'success');
   169→          return { success: true, url: iframeWindow?.location.href || '', html: iframeDoc.documentElement.outerHTML };
   170→        }
   171→        default:
   172→          return { success: false, error: `نوع الأكشن غير مدعوم: ${action.type}` };
   173→      }
   174→    } catch (err: any) {
